const Leads = () => {
    const [sorting, setSorting] = useState<SortingState>([]);
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState('');

    const data = useMemo(
        () => LEADS.filter(l => l.contact.toLowerCase().includes(search.toLowerCase())),
        [search]
