                />
                <Button variant="secondary" size="sm">
                    Filters
                </Button>
            </DataTable.ToolBar>

            <DataTable.Table />

            <DataTable.Footer>
                <Pagination
                    totalCount={LEADS.length}
                    currentPage={page}
                    pageSize={10}
                    onPageChange={setPage}
                />
            </DataTable.Footer>
        </DataTable.Root>
